// Report.jsx
import React, { useState, useEffect, useRef } from 'react';
import './Report.css';

const Report = ({ user }) => {
  const [timeRange, setTimeRange] = useState('monthly');
  const [activeTab, setActiveTab] = useState('overview');
  const [isLoading, setIsLoading] = useState(true);
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [isUnlocking, setIsUnlocking] = useState(false);
  const [showPremiumModal, setShowPremiumModal] = useState(false);
  const [copiedToClipboard, setCopiedToClipboard] = useState(false);
  const [streak, setStreak] = useState(0);
  const [coins, setCoins] = useState(0);
  const [completedActivities, setCompletedActivities] = useState(0);
  const [overallMoodScore, setOverallMoodScore] = useState(70);
  
  const [reportData, setReportData] = useState(null);
  
  // AI Deep Analysis State
  const [aiAnalysisText, setAiAnalysisText] = useState("");
  const [isGeneratingAnalysis, setIsGeneratingAnalysis] = useState(false);
  
  const reportRef = useRef(null);

  useEffect(() => {
    fetchReportData();
  }, [user]);

  const fetchReportData = async () => {
    try {
      setIsLoading(true);
      const response = await fetch(`http://localhost:5000/api/report?user_id=${user?.id || 1}`);
      const data = await response.json();
      
      if (data.status === 'success') {
        setReportData(data);
        setStreak(data.streak);
        setCoins(data.coins);
        setCompletedActivities(data.completed_activities);
        setOverallMoodScore(data.overall_score);
      }
    } catch (error) {
      console.error("Failed to fetch report data:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const generateActivityData = () => {
    const activitiesList = [
      { type: 'Meditation', duration: '5 min', coins: 10, mood: '😌' },
      { type: 'Journaling', duration: '7 min', coins: 15, mood: '😊' },
      { type: 'Mood Check-in', duration: '2 min', coins: 5, mood: '😊' },
    ];
    // Return sample if empty, else generate based on days tracked
    if (!reportData || reportData.mood_data.length === 0) return [];
    
    return reportData.mood_data.map(d => {
      const act = activitiesList[Math.floor(Math.random() * activitiesList.length)];
      return {
        date: d.date,
        type: act.type,
        duration: act.duration,
        coins: Math.floor(d.score / 10),
        mood: d.mood.split(' ')[0]
      };
    }).reverse();
  };

  const generateAchievements = () => {
    return [
      { id: 1, name: '7-Day Streak', earned: streak >= 7, icon: '🔥', description: 'Logged activities for 7 consecutive days' },
      { id: 2, name: 'Meditation Master', earned: completedActivities > 5, icon: '🧘', description: 'Completed a lot of sessions' },
      { id: 3, name: 'Mood Tracker', earned: true, icon: '📊', description: 'Consistently using MoodMate' },
      { id: 4, name: 'Early Bird', earned: false, icon: '🌅', description: 'Complete 5 morning routines' },
      { id: 5, name: 'Wellness Warrior', earned: streak >= 30, icon: '🛡️', description: '30-day streak' },
      { id: 6, name: 'Sleep Champion', earned: false, icon: '🌙', description: 'Track sleep for 14 nights' }
    ];
  };

  const moodData = reportData ? reportData.mood_data : [];
  const moodDistribution = reportData ? reportData.mood_distribution : {};
  const activities = generateActivityData();
  const achievements = generateAchievements();

  // Generate AI insights
  const aiInsights = [
    "Your mood improves significantly when you maintain your check-in streak.",
    "You tend to feel more 'Calm' after earning more coins in the evening.",
    "Connecting with the community might help on days you feel 'Neutral'.",
    `You've earned ${coins} coins total! You are building great habits.`
  ];

  // Generate predictions
  const predictions = [
    `Based on your patterns, your estimated mood score will stay around ${overallMoodScore + 5}.`,
    "You're on track to hit a new milestone in a few days.",
    "Continuing at this rate, you'll reach the next reward tier."
  ];

  // Handle PDF download — inline feedback instead of alert()
  const handleDownloadPDF = () => {
    setIsGeneratingPDF(true);
    setTimeout(() => {
      setIsGeneratingPDF(false);
      // Show inline toast
      const toast = document.createElement('div');
      toast.textContent = '✅ PDF ready! (Feature coming soon)';
      toast.style.cssText = 'position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:#1e293b;color:white;padding:12px 24px;border-radius:12px;font-size:14px;z-index:9999;box-shadow:0 8px 30px rgba(0,0,0,0.2)';
      document.body.appendChild(toast);
      setTimeout(() => document.body.removeChild(toast), 3000);
    }, 1500);
  };

  // Handle sharing with coach — inline feedback
  const handleShareWithCoach = () => {
    setIsSharing(true);
    setTimeout(() => {
      setIsSharing(false);
      setCopiedToClipboard(true);
      const toast = document.createElement('div');
      toast.textContent = '🔗 Share link copied! Send it to your therapist.';
      toast.style.cssText = 'position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:#4f46e5;color:white;padding:12px 24px;border-radius:12px;font-size:14px;z-index:9999;box-shadow:0 8px 30px rgba(79,70,229,0.3)';
      document.body.appendChild(toast);
      setTimeout(() => { document.body.removeChild(toast); setCopiedToClipboard(false); }, 3000);
    }, 1000);
  };

  // Handle unlocking premium
  const handleUnlockPremium = () => {
    setIsUnlocking(true);
    
    // Simulate unlocking process
    setTimeout(() => {
      setIsUnlocking(false);
      setShowPremiumModal(true);
    }, 1500);
  };

  const showToast = (msg, color = '#1e293b') => {
    const toast = document.createElement('div');
    toast.textContent = msg;
    toast.style.cssText = `position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:${color};color:white;padding:12px 24px;border-radius:12px;font-size:14px;z-index:9999;box-shadow:0 8px 30px rgba(0,0,0,0.2);white-space:nowrap`;
    document.body.appendChild(toast);
    setTimeout(() => document.body.removeChild(toast), 3000);
  };

  // Handle challenge actions
  const handleChallengeAction = (action) => {
    switch(action) {
      case 'meditation': showToast('🧘 Opening Meditation... go to AI Coach tab!', '#7c3aed'); break;
      case 'sleep': showToast('🌙 Sleep Analysis coming in next update!', '#1e40af'); break;
      case 'goals': showToast('🎯 Goal Setting — coming soon!', '#065f46'); break;
      default: break;
    }
  };

  const generateDeepAnalysis = async () => {
    setIsGeneratingAnalysis(true);
    setAiAnalysisText("");
    try {
      const response = await fetch(`http://localhost:5000/api/report/analysis`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({ user_id: user?.id || 1 })
      });
      const data = await response.json();
      if (data.status === 'success') {
        setAiAnalysisText(data.analysis);
      } else {
        setAiAnalysisText("Sorry, I could not analyze your history right now.");
      }
    } catch (err) {
      console.error("Deep analysis generation error:", err);
      setAiAnalysisText("Error reaching backend servers.");
    } finally {
      setIsGeneratingAnalysis(false);
    }
  };

  if (isLoading) {
    return (
      <div className="report-loading">
        <div className="loading-spinner"></div>
        <p>Generating your premium wellness report...</p>
      </div>
    );
  }

  return (
    <div className="report-full-page" ref={reportRef}>
      {/* Header Section */}
      <div className="report-header">
        <div className="header-content">
          <h1>Hey {user?.username || 'there'}! Here's your mental wellness snapshot 🧠💫</h1>
          <p>Your personalized wellness report for {new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}</p>
        </div>
        <div className="time-range-selector">
          <button 
            className={timeRange === 'weekly' ? 'active' : ''}
            onClick={() => setTimeRange('weekly')}
          >
            Weekly
          </button>
          <button 
            className={timeRange === 'monthly' ? 'active' : ''}
            onClick={() => setTimeRange('monthly')}
          >
            Monthly
          </button>
          <button 
            className={timeRange === 'quarterly' ? 'active' : ''}
            onClick={() => setTimeRange('quarterly')}
          >
            Quarterly
          </button>
        </div>
      </div>

      {/* 7-DAY MOOD REPLAY: VIRAL RETENTION HOOK */}
      <div style={{ background: 'linear-gradient(135deg, #ec4899, #8b5cf6)', padding: '25px 30px', borderRadius: '24px', margin: '15px 0 30px 0', color: 'white', textAlign: 'center', boxShadow: '0 8px 30px rgba(139, 92, 246, 0.25)', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: '-15px', right: '-10px', fontSize: '100px', opacity: '0.08', transform: 'rotate(15deg)' }}>🧠</div>
        
        <h2 style={{ fontSize: '24px', fontWeight: '800', margin: '0 0 5px 0', letterSpacing: '-0.5px' }}>Your 7-Day Mood Replay</h2>
        <p style={{ fontSize: '14px', opacity: '0.85', margin: '0 0 20px 0', fontWeight: '500' }}>This is how you felt last week. Look how far you've come.</p>
        
        <div style={{ display: 'flex', justifyContent: 'center', gap: '8px', flexWrap: 'nowrap', marginBottom: '20px', position: 'relative', zIndex: 2, overflowX: 'auto', padding: '5px' }}>
          {moodData.slice(-7).map((day, idx) => (
            <div key={idx} style={{ background: 'rgba(255,255,255,0.12)', padding: '10px 12px', borderRadius: '16px', backdropFilter: 'blur(8px)', border: '1px solid rgba(255,255,255,0.2)', minWidth: '70px', transition: 'all 0.2s' }}>
              <div style={{ fontSize: '11px', opacity: 0.8, marginBottom: '4px', fontWeight: '600' }}>Day {idx+1}</div>
              <div style={{ fontSize: '24px', margin: '2px 0' }}>{day.mood.split(' ')[0]}</div>
              <div style={{ fontSize: '13px', fontWeight: '800' }}>{day.score}%</div>
            </div>
          ))}
        </div>
        
        <div style={{ background: 'rgba(0,0,0,0.15)', padding: '15px 20px', borderRadius: '16px', display: 'inline-block', width: '100%', maxWidth: '600px', border: '1px solid rgba(255,255,255,0.1)' }}>
          <h3 style={{ margin: '0 0 8px 0', color: '#fcd34d', fontSize: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px' }}>💡 Insight</h3>
          <p style={{ margin: 0, fontSize: '14px', lineHeight: '1.5', opacity: 0.95 }}>Looking back at your week — every check-in you made shifted your trajectory. That consistency? That’s a real skill. <strong>{moodData[0]?.mood?.split(' ')[1] || 'uncertain'}</strong> to where you are now.</p>
        </div>
        
        <div style={{ marginTop: '20px' }}>
            <button 
              onClick={() => {
                setIsSharing(true);
                setTimeout(() => setIsSharing(false), 3000);
              }}
              style={{ background: isSharing ? '#10b981' : 'white', color: isSharing ? 'white' : '#8b5cf6', fontWeight: '700', padding: '12px 30px', borderRadius: '100px', border: 'none', cursor: 'pointer', fontSize: '15px', boxShadow: '0 4px 15px rgba(0,0,0,0.1)', transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)', display: 'inline-flex', alignItems: 'center', gap: '8px' }}
            >
              {isSharing ? '✓ Generation Complete' : 'Share to Instagram 📸'}
            </button>
        </div>
      </div>

      {/* Summary Section */}
      <div className="summary-section">
        <div className="mood-score">
          <h2>Overall Mood Score</h2>
          {/* Animated SVG score ring */}
          <div className="score-ring-wrapper">
            <svg className="score-ring-svg" viewBox="0 0 120 120">
              <defs>
                <linearGradient id="scoreGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                  <stop offset="0%" stopColor="#8b5cf6" />
                  <stop offset="100%" stopColor="#ec4899" />
                </linearGradient>
              </defs>
              <circle className="score-ring-bg" cx="60" cy="60" r="54" />
              <circle
                className="score-ring-fill"
                cx="60" cy="60" r="54"
                style={{ '--dash-offset': `${339.292 * (1 - overallMoodScore / 100)}` }}
              />
            </svg>
            <div className="score-center">
              <span className="score">{overallMoodScore}</span>
              <span className="out-of">/100</span>
            </div>
          </div>
          <div className="score-label">
            {overallMoodScore >= 80 ? '✨ Excellent' :
             overallMoodScore >= 60 ? '👍 Good' :
             overallMoodScore >= 40 ? '🌱 Fair' : '💪 Keep Going'}
          </div>
        </div>

        <div className="highlights">
          <h2>Top Highlights</h2>
          <div className="highlight-cards">
            <div className="highlight-card">
              <span className="icon">🔥</span>
              <span className="value">{streak} days</span>
              <span className="label">Current Streak</span>
            </div>
            <div className="highlight-card">
              <span className="icon">✅</span>
              <span className="value">{completedActivities} completed</span>
              <span className="label">Activities</span>
            </div>
            <div className="highlight-card">
              <span className="icon">🪙</span>
              <span className="value">{coins} earned</span>
              <span className="label">Coins</span>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="report-tabs">
        <button 
          className={activeTab === 'overview' ? 'active' : ''}
          onClick={() => setActiveTab('overview')}
        >
          Overview
        </button>
        <button 
          className={activeTab === 'trends' ? 'active' : ''}
          onClick={() => setActiveTab('trends')}
        >
          Trends
        </button>
        <button 
          className={activeTab === 'activities' ? 'active' : ''}
          onClick={() => setActiveTab('activities')}
        >
          Activities
        </button>
        <button 
          className={activeTab === 'achievements' ? 'active' : ''}
          onClick={() => setActiveTab('achievements')}
        >
          Achievements
        </button>
        <button 
          className={activeTab === 'insights' ? 'active' : ''}
          onClick={() => setActiveTab('insights')}
        >
          AI Insights
        </button>
      </div>

      {/* Tab Content */}
      <div className="tab-content-full">
        {activeTab === 'overview' && (
          <div className="overview-tab">
            <div className="chart-container">
              <h3>Mood Trend</h3>
              <div className="mood-trend-chart">
                {moodData.slice(-7).length > 0 ? moodData.slice(-7).map((day, i) => (
                  <div key={i} className="chart-bar">
                    <div
                      className="bar"
                      style={{ height: `${day.score}%` }}
                      data-score={day.score}
                    ></div>
                    <span className="day-label">{day.date?.split('/')[1] || `D${i+1}`}</span>
                  </div>
                )) : (
                  <div className="mood-trend-chart-empty">
                    <div className="empty-icon">📊</div>
                    <p>Log your first mood to see trends here</p>
                  </div>
                )}
              </div>
            </div>

            <div className="mood-distribution">
              <h3>Mood Distribution</h3>
              <div className="distribution-chart">
                {Object.entries(moodDistribution).map(([mood, count], i) => {
                  const percentage = (count / moodData.length) * 100;
                  return (
                    <div key={i} className="distribution-item">
                      <div className="mood-label">{mood}</div>
                      <div className="distribution-bar">
                        <div 
                          className="fill" 
                          style={{ width: `${percentage}%` }}
                        ></div>
                      </div>
                      <div className="percentage">{percentage.toFixed(1)}%</div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'trends' && (
          <div className="trends-tab">
            <h3>Mood Trends Over Time</h3>
            <div className="calendar-heatmap">
              <div className="heatmap-header">Last 30 Days</div>
              <div className="heatmap-grid">
                {moodData.map((day, i) => (
                  <div 
                    key={i} 
                    className="heatmap-cell"
                    style={{ 
                      backgroundColor: `hsl(${day.score * 1.2}, 70%, 60%)`,
                      border: day.score > 80 ? '2px solid gold' : 'none'
                    }}
                    title={`${day.date}: Score ${day.score}`}
                  ></div>
                ))}
              </div>
              <div className="heatmap-legend">
                <span>Low</span>
                <div className="gradient-bar"></div>
                <span>High</span>
              </div>
            </div>
            
            <div className="trend-analysis">
              <h3>Weekly Analysis</h3>
              <div className="trend-cards">
                <div className="trend-card positive">
                  <span className="trend-icon">📈</span>
                  <div className="trend-content">
                    <h4>Positive Trend</h4>
                    <p>Your mood has improved by 15% compared to last week</p>
                  </div>
                </div>
                <div className="trend-card neutral">
                  <span className="trend-icon">⏰</span>
                  <div className="trend-content">
                    <h4>Consistent Routine</h4>
                    <p>You've maintained a consistent activity schedule</p>
                  </div>
                </div>
                <div className="trend-card improvement">
                  <span className="trend-icon">💤</span>
                  <div className="trend-content">
                    <h4>Sleep Quality</h4>
                    <p>Your sleep score has increased by 20% this month</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'activities' && (
          <div className="activities-tab">
            <h3>Activity History</h3>
            <div className="activities-table">
              {activities.length > 0 ? (
                <>
                  <div className="table-header">
                    <span>Date</span>
                    <span>Activity</span>
                    <span>Duration</span>
                    <span>Mood</span>
                    <span>Coins</span>
                  </div>
                  {activities.slice(0, 20).map((activity, i) => (
                    <div key={i} className="table-row">
                      <span>{activity.date}</span>
                      <span>{activity.type}</span>
                      <span>{activity.duration}</span>
                      <span>{activity.mood}</span>
                      <span style={{ color: '#fbbf24', fontWeight: '700' }}>+{activity.coins}</span>
                    </div>
                  ))}
                </>
              ) : (
                <div className="activities-empty">
                  <div className="e-icon">🏃</div>
                  <p>Complete activities to see your history here</p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'achievements' && (
          <div className="achievements-tab">
            <h3>Your Achievements</h3>
            <div className="achievements-grid">
              {achievements.map(achievement => (
                <div 
                  key={achievement.id} 
                  className={`achievement-card ${achievement.earned ? 'earned' : 'locked'}`}
                >
                  <div className="achievement-icon">{achievement.icon}</div>
                  <div className="achievement-info">
                    <h4>{achievement.name}</h4>
                    <p>{achievement.description}</p>
                  </div>
                  <div className="achievement-status">
                    {achievement.earned ? '✅ Earned' : '🔒 Locked'}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'insights' && (
          <div className="insights-tab">
            <h3>AI-Powered Insights</h3>
            <div className="insights-container">
              {aiInsights.map((insight, i) => (
                <div key={i} className="insight-card">
                  <div className="insight-icon">💡</div>
                  <p>{insight}</p>
                </div>
              ))}
            </div>

            <h3>Predictions & Recommendations</h3>
            <div className="predictions-container">
              {predictions.map((prediction, i) => (
                <div key={i} className="prediction-card">
                  <div className="prediction-icon">🔮</div>
                  <p>{prediction}</p>
                </div>
              ))}
            </div>

            <div className="deep-analysis-section">
              <h3>Deep AI Emotional Journaling</h3>
              <p>Have your personalized cognitive behavioral therapist write an entire wellness thesis based on your past week of logs.</p>
              
              {!aiAnalysisText && (
                <button 
                  className={`action-btn ${isGeneratingAnalysis ? 'loading' : 'primary-glow'}`} 
                  onClick={generateDeepAnalysis}
                  disabled={isGeneratingAnalysis}
                  style={{ marginTop: '15px', backgroundColor: '#7C3AED', width: '100%', padding: '15px' }}
                >
                  {isGeneratingAnalysis ? '🧠 Analyzing cognitive data...' : '✨ Generate Deep Analysis'}
                </button>
              )}

              {aiAnalysisText && (
                <div className="analysis-result-box" style={{ marginTop: '20px', padding: '20px', backgroundColor: '#312E81', borderRadius: '15px', color: '#E0E7FF', lineHeight: '1.6' }}>
                  {aiAnalysisText.split('\n').map((line, i) => {
                    if (line.startsWith('#')) {
                      return <h4 key={i} style={{ color: '#FCD34D', marginTop: '10px' }}>{line.replace(/#/g, '')}</h4>;
                    }
                    if (line.startsWith('-') || line.startsWith('*')) {
                      return <li key={i} style={{ marginLeft: '15px' }}>{line.substring(1)}</li>;
                    }
                    return <p key={i} style={{ marginBottom: '10px' }}>{line}</p>;
                  })}
                </div>
              )}
            </div>

            <div className="action-buttons">
              <button className="action-btn" onClick={() => handleChallengeAction('meditation')}>
                Try Meditation Challenge
              </button>
              <button className="action-btn" onClick={() => handleChallengeAction('sleep')}>
                View Sleep Analysis
              </button>
              <button className="action-btn" onClick={() => handleChallengeAction('goals')}>
                Set New Goals
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Download/Share Section */}
      <div className="report-actions">
        <button 
          className={`download-btn ${isGeneratingPDF ? 'loading' : ''}`}
          onClick={handleDownloadPDF}
          disabled={isGeneratingPDF}
        >
          {isGeneratingPDF ? (
            <>
              <span className="spinner"></span>
              Generating PDF...
            </>
          ) : (
            <>
              📄 Download PDF Report
            </>
          )}
        </button>
        <button 
          className={`share-btn ${isSharing ? 'loading' : ''}`}
          onClick={handleShareWithCoach}
          disabled={isSharing}
        >
          {isSharing ? (
            <>
              <span className="spinner"></span>
              Preparing share...
            </>
          ) : copiedToClipboard ? (
            '✓ Copied to Clipboard!'
          ) : (
            '↗ Share with Coach'
          )}
        </button>
        {!user.is_premium && (
          <button 
            className={`premium-btn ${isUnlocking ? 'loading' : ''}`}
            onClick={handleUnlockPremium}
            disabled={isUnlocking}
          >
            {isUnlocking ? (
              <>
                <span className="spinner"></span>
                Unlocking...
              </>
            ) : (
              '🔓 Unlock Advanced Analytics'
            )}
          </button>
        )}
      </div>

      {/* Premium Modal */}
      {showPremiumModal && (
        <div className="modal-overlay">
          <div className="premium-modal">
            <button className="modal-close" onClick={() => setShowPremiumModal(false)}>×</button>
            <div className="modal-content">
              <div className="modal-icon">✨</div>
              <h2>Unlock Premium Features</h2>
              <p>Upgrade to access advanced analytics, personalized insights, and more detailed reports.</p>
              <div className="premium-features">
                <div className="feature">
                  <span className="feature-icon">📊</span>
                  <span>Advanced Analytics</span>
                </div>
                <div className="feature">
                  <span className="feature-icon">🔍</span>
                  <span>Detailed Insights</span>
                </div>
                <div className="feature">
                  <span className="feature-icon">📈</span>
                  <span>Trend Predictions</span>
                </div>
                <div className="feature">
                  <span className="feature-icon">💎</span>
                  <span>Exclusive Content</span>
                </div>
              </div>
              <button className="upgrade-btn">🌟 Upgrade Now — ₹99/month</button>
              <p className="modal-note">7-day free trial • Cancel anytime</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Report;
